import redis
from redis.cluster import RedisCluster
from redis.sentinel import Sentinel
import hashlib
import secrets
import json
from datetime import datetime, timedelta
from typing import Optional, Dict, Any, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class RedisCacheService:
    def __init__(self, 
                 cluster_nodes: Optional[List[Dict[str, Any]]] = None,
                 sentinel_nodes: Optional[List[tuple]] = None,
                 master_name: Optional[str] = None,
                 password: Optional[str] = None,
                 use_cluster: bool = True,
                 ssl: bool = True,
                 decode_responses: bool = True):
        
        self.password = password
        self.ssl = ssl
        self.decode_responses = decode_responses
        
        if use_cluster and cluster_nodes:
            self.client = self._init_cluster(cluster_nodes)
        elif sentinel_nodes and master_name:
            self.client = self._init_sentinel(sentinel_nodes, master_name)
        else:
            self.client = redis.Redis(
                host='localhost',
                port=6379,
                password=password,
                ssl=ssl,
                decode_responses=decode_responses
            )
        
        logger.info("Redis connection initialized")
    
    def _init_cluster(self, cluster_nodes: List[Dict[str, Any]]) -> RedisCluster:
        startup_nodes = [
            {"host": node["host"], "port": node["port"]} 
            for node in cluster_nodes
        ]
        
        return RedisCluster(
            startup_nodes=startup_nodes,
            password=self.password,
            ssl=self.ssl,
            decode_responses=self.decode_responses,
            skip_full_coverage_check=True
        )
    
    def _init_sentinel(self, sentinel_nodes: List[tuple], master_name: str) -> redis.Redis:
        sentinel = Sentinel(
            sentinel_nodes,
            socket_timeout=0.5,
            password=self.password,
            ssl=self.ssl
        )
        
        return sentinel.master_for(
            master_name,
            socket_timeout=0.5,
            password=self.password,
            ssl=self.ssl,
            decode_responses=self.decode_responses
        )
    
    def _hash_key(self, key: str) -> str:
        return hashlib.sha256(key.encode()).hexdigest()
    
    def set_session_token(self, 
                         user_id: str, 
                         token: str, 
                         ttl_hours: int = 24,
                         metadata: Optional[Dict[str, Any]] = None) -> bool:
        key = f"session:{self._hash_key(user_id)}"
        
        session_data = {
            "token": token,
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "expires_in": ttl_hours * 3600
        }
        
        if metadata:
            session_data["metadata"] = metadata
        
        try:
            result = self.client.setex(
                key,
                timedelta(hours=ttl_hours),
                json.dumps(session_data)
            )
            logger.info(f"Session token set for user: {user_id[:8]}...")
            return result
        except Exception as e:
            logger.error(f"Error setting session token: {e}")
            return False
    
    def get_session_token(self, user_id: str) -> Optional[Dict[str, Any]]:
        key = f"session:{self._hash_key(user_id)}"
        
        try:
            data = self.client.get(key)
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            logger.error(f"Error getting session token: {e}")
            return None
    
    def invalidate_session(self, user_id: str) -> bool:
        key = f"session:{self._hash_key(user_id)}"
        
        try:
            result = self.client.delete(key)
            logger.info(f"Session invalidated for user: {user_id[:8]}...")
            return result > 0
        except Exception as e:
            logger.error(f"Error invalidating session: {e}")
            return False
    
    def set_api_key(self, 
                    api_key_id: str, 
                    api_key: str, 
                    user_id: str,
                    permissions: List[str],
                    ttl_days: int = 365) -> bool:
        key = f"apikey:{self._hash_key(api_key_id)}"
        
        api_key_data = {
            "api_key": api_key,
            "api_key_id": api_key_id,
            "user_id": user_id,
            "permissions": permissions,
            "created_at": datetime.utcnow().isoformat(),
            "expires_in": ttl_days * 86400
        }
        
        try:
            result = self.client.setex(
                key,
                timedelta(days=ttl_days),
                json.dumps(api_key_data)
            )
            
            user_api_keys_key = f"user_apikeys:{self._hash_key(user_id)}"
            self.client.sadd(user_api_keys_key, api_key_id)
            self.client.expire(user_api_keys_key, timedelta(days=ttl_days))
            
            logger.info(f"API key set for user: {user_id[:8]}...")
            return result
        except Exception as e:
            logger.error(f"Error setting API key: {e}")
            return False
    
    def get_api_key(self, api_key_id: str) -> Optional[Dict[str, Any]]:
        key = f"apikey:{self._hash_key(api_key_id)}"
        
        try:
            data = self.client.get(key)
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            logger.error(f"Error getting API key: {e}")
            return None
    
    def validate_api_key(self, api_key: str, required_permission: Optional[str] = None) -> Optional[Dict[str, Any]]:
        api_key_id = self._hash_key(api_key)
        api_key_data = self.get_api_key(api_key_id)
        
        if not api_key_data:
            return None
        
        if api_key_data.get("api_key") != api_key:
            return None
        
        if required_permission and required_permission not in api_key_data.get("permissions", []):
            return None
        
        return api_key_data
    
    def revoke_api_key(self, api_key_id: str, user_id: str) -> bool:
        key = f"apikey:{self._hash_key(api_key_id)}"
        user_api_keys_key = f"user_apikeys:{self._hash_key(user_id)}"
        
        try:
            self.client.delete(key)
            self.client.srem(user_api_keys_key, api_key_id)
            logger.info(f"API key revoked: {api_key_id[:8]}...")
            return True
        except Exception as e:
            logger.error(f"Error revoking API key: {e}")
            return False
    
    def get_user_api_keys(self, user_id: str) -> List[str]:
        user_api_keys_key = f"user_apikeys:{self._hash_key(user_id)}"
        
        try:
            return list(self.client.smembers(user_api_keys_key))
        except Exception as e:
            logger.error(f"Error getting user API keys: {e}")
            return []
    
    def cache_data(self, 
                   key: str, 
                   data: Any, 
                   ttl_seconds: int = 3600,
                   namespace: str = "cache") -> bool:
        cache_key = f"{namespace}:{key}"
        
        try:
            if isinstance(data, (dict, list)):
                data = json.dumps(data)
            
            result = self.client.setex(
                cache_key,
                timedelta(seconds=ttl_seconds),
                data
            )
            logger.info(f"Data cached: {cache_key}")
            return result
        except Exception as e:
            logger.error(f"Error caching data: {e}")
            return False
    
    def get_cached_data(self, key: str, namespace: str = "cache") -> Optional[Any]:
        cache_key = f"{namespace}:{key}"
        
        try:
            data = self.client.get(cache_key)
            if data:
                try:
                    return json.loads(data)
                except json.JSONDecodeError:
                    return data
            return None
        except Exception as e:
            logger.error(f"Error getting cached data: {e}")
            return None
    
    def delete_cached_data(self, key: str, namespace: str = "cache") -> bool:
        cache_key = f"{namespace}:{key}"
        
        try:
            result = self.client.delete(cache_key)
            return result > 0
        except Exception as e:
            logger.error(f"Error deleting cached data: {e}")
            return False
    
    def increment_rate_limit(self, 
                            identifier: str, 
                            limit: int = 100, 
                            window_seconds: int = 60) -> Dict[str, Any]:
        key = f"ratelimit:{self._hash_key(identifier)}"
        
        try:
            pipe = self.client.pipeline()
            pipe.incr(key)
            pipe.expire(key, window_seconds)
            results = pipe.execute()
            
            current_count = results[0]
            remaining = max(0, limit - current_count)
            
            return {
                "allowed": current_count <= limit,
                "current": current_count,
                "limit": limit,
                "remaining": remaining,
                "reset_in": self.client.ttl(key)
            }
        except Exception as e:
            logger.error(f"Error checking rate limit: {e}")
            return {"allowed": True, "current": 0, "limit": limit, "remaining": limit}
    
    def set_user_data(self, 
                      user_id: str, 
                      data: Dict[str, Any], 
                      ttl_hours: int = 24) -> bool:
        key = f"user:{self._hash_key(user_id)}"
        
        try:
            result = self.client.setex(
                key,
                timedelta(hours=ttl_hours),
                json.dumps(data)
            )
            logger.info(f"User data set: {user_id[:8]}...")
            return result
        except Exception as e:
            logger.error(f"Error setting user data: {e}")
            return False
    
    def get_user_data(self, user_id: str) -> Optional[Dict[str, Any]]:
        key = f"user:{self._hash_key(user_id)}"
        
        try:
            data = self.client.get(key)
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            logger.error(f"Error getting user data: {e}")
            return None
    
    def health_check(self) -> Dict[str, Any]:
        try:
            ping_result = self.client.ping()
            info = self.client.info()
            
            return {
                "status": "healthy" if ping_result else "unhealthy",
                "connected_clients": info.get("connected_clients", 0),
                "used_memory_human": info.get("used_memory_human", "unknown"),
                "uptime_in_seconds": info.get("uptime_in_seconds", 0)
            }
        except Exception as e:
            logger.error(f"Health check failed: {e}")
            return {"status": "unhealthy", "error": str(e)}
    
    def close(self):
        try:
            self.client.close()
            logger.info("Redis connection closed")
        except Exception as e:
            logger.error(f"Error closing connection: {e}")


def generate_secure_token(length: int = 32) -> str:
    return secrets.token_urlsafe(length)


def generate_api_key() -> tuple:
    api_key = secrets.token_urlsafe(32)
    api_key_id = hashlib.sha256(api_key.encode()).hexdigest()
    return api_key, api_key_id


